	display: block;
	z-index: 0;
	content: "";
	box-sizing: border-box;
	position: absolute;

	inline-size: var(--mod-radio-button-control-size, var(--spectrum-radio-button-control-size));
	block-size: var(--mod-radio-button-control-size, var(--spectrum-radio-button-control-size));

	background-color: var(--mod-radio-button-background-color, var(--spectrum-radio-button-background-color));

	border-radius: 50%;
	border-width: var(--mod-radio-border-width, var(--spectrum-radio-border-width));
	border-color: var(--highcontrast-radio-button-border-color-default, var(--mod-radio-button-border-color-default, var(--spectrum-radio-button-border-color-default)));
	border-style: solid;

	transition:
		border var(--mod-radio-animation-duration, var(--spectrum-radio-animation-duration)) ease-in-out,
		box-shadow var(--mod-radio-animation-duration, var(--spectrum-radio-animation-duration)) ease-in-out;
}

&:disabled,
    &.is-disabled {
      background-color: xvar(
        --spectrum-high-contrast-gray-text,
        var(--spectrum-actionbutton-emphasized-background-color-selected-disabled)
      );
      border-color: xvar(
        --spectrum-high-contrast-gray-text,
        var(--spectrum-actionbutton-emphasized-border-color-selected-disabled)
      );
      color: xvar(
        --spectrum-high-contrast-button-face,
        var(--spectrum-actionbutton-emphasized-text-color-selected-disabled)
      );

      .spectrum-Icon {
        fill: xvar(
          --spectrum-high-contrast-button-face,
          var(--spectrum-actionbutton-emphasized-icon-color-selected-disabled)
        );
      }
